1701→\begin{lemma}
1702→  \label{thm:ind-etale-strictly-henselian-localization-isom}
1703→  \uses{def:ind-etale,def:strictly-henselian-local-ring,def:identify-local-rings}
1704→  Let \(A\) be a strictly henselian local ring. Let \(A \to B\) be an ind-étale ring map.
1705→  Let $\n$ be an maximal ideal of $B$ lying over the maximal ideal $\m$ of $A$.
1706→  Then the map $A \to B_\n$ is isomorphism.
1707→\end{lemma}
1708→
1709→\begin{proof}
1710→  \uses{thm:etale-over-strictly-henselian-localization-isom}
1711→  Write $B = \colim_i B_i$ as a filtered colimit of étale $A$-algebras $B_i$. Since localization commutes with colimits, we have $B_\n = \colim_i (B_i)_{\n_i}$ where $\n_i$ is the restriction of $\n$ to $B_i$. Then use \Cref{thm:etale-over-strictly-henselian-localization-isom} to conclude each $B_i$ is isomorphic to $A$.
1712→\end{proof}
