1889→\begin{lemma}
1890→    Let $k$ be a field and $A$ an ind-étale, local $k$-algebra. Then $A$ is
1891→    a separable algebraic field extension of $k$.
1892→    \uses{def:ind-etale}
1893→    \label{lemma:field-local-ind-etale}
1894→    \lean{Algebra.IndEtale.isSeparable}
1895→    \leanok
1896→\end{lemma}
1897→
1898→\begin{proof}
1899→    Let $A = \colim_i A_i$ such that $A_i$ is an étale $k$-algebra for all $i$.
1900→    Let $\mathfrak{m}$ be the maximal ideal of $A$. Since localization commutes with colimits,
1901→    we obtain $A = A_{\mathfrak{m}} = \colim_i (A_i)_{\mathfrak{m}_i}$ where
1902→    $\mathfrak{m}_i$ is the restriction of $\mathfrak{m}$ to $A_i$. Since $A_i$ is étale over $k$,
1903→    it is a finite product of finite separable extensions of $k$, hence $(A_i)_{\mathfrak{m}_i}$
1904→    is a finite separable extension of $k$. Since a filtered colimit of finite separable
1905→    extensions is an algebraic separable extension, we conclude.
1906→\end{proof}
